import * as React from 'react';
import type { Environment, Table, EnvironmentStatus, TableStatus } from '@/types/environments';
import { useQuery, useMutation } from 'convex/react';
import { api } from '@/convex/_generated/api';
import { useEstablishments } from '@/hooks/useEstablishments';
import { Id } from '@/convex/_generated/dataModel';

const calculateCapacity = (width: number, height: number) => {
    return Math.floor((width * height) / 10000);
};

const mapEnvStatusToConvex = (status?: EnvironmentStatus) => {
    if (status === 'Abierto') return 'active';
    if (status === 'Cerrado') return 'inactive';
    return undefined;
};

const mapTableStatusToConvex = (status?: TableStatus) => {
    if (status === 'Libre') return 'free';
    if (status === 'Ocupada') return 'occupied';
    if (status === 'Reservada') return 'reserved';
    if (status === 'Mantenimiento') return 'maintenance';
    if (status === 'Inactiva') return 'maintenance';
    return undefined;
};

export const useEnvironments = () => {
    const { activeEstablishment } = useEstablishments();
    const establishmentId = activeEstablishment?.id as Id<"establishments"> | undefined;

    const convexEnvironments = useQuery(api.environments.getEnvironmentsByEstablishment, 
        establishmentId ? { establishmentId } : "skip"
    );

    const createEnvMutation = useMutation(api.environments.createEnvironment);
    const updateEnvMutation = useMutation(api.environments.updateEnvironment);
    const deleteEnvMutation = useMutation(api.environments.deleteEnvironment);

    const createTableMutation = useMutation(api.environments.createTable);
    const updateTableMutation = useMutation(api.environments.updateTable);
    const deleteTableMutation = useMutation(api.environments.deleteTable);

    const environments = (convexEnvironments || []) as Environment[];
    const isLoadingEnvironments = convexEnvironments === undefined;

    const addEnvironment = async () => {
        if (!establishmentId) return;
        const newEnvName = `Ambiente ${environments.length + 1}`;
        const newEnvId = await createEnvMutation({
            establishmentId,
            name: newEnvName,
            capacity: 0,
            status: 'active',
            icon: 'Utensils',
            color: 'violet-500'
        });
        return newEnvId;
    };

    const removeEnvironment = async (idToRemove: string) => {
        await deleteEnvMutation({ environmentId: idToRemove as Id<"environments"> });
    };

    const updateEnvironment = async (envId: string, updates: Partial<Environment>) => {
        await updateEnvMutation({
            environmentId: envId as Id<"environments">,
            name: updates.name,
            capacity: updates.capacity,
            status: mapEnvStatusToConvex(updates.status),
            icon: updates.icon,
            color: updates.color,
        });
    };

    const addTable = async (envId: string, isObject: boolean = false, objectType?: string) => {
        const env = environments.find(e => e.id === envId);
        if (!env) return;

        let tableNumber = 1;
        if (!isObject) {
            const numbers = env.tables.filter(t => !t.isObject).map(t => t.number);
            while (numbers.includes(tableNumber)) tableNumber++;
        }

        const newTableId = await createTableMutation({
            environmentId: envId as Id<"environments">,
            number: isObject ? 0 : tableNumber,
            capacity: calculateCapacity(80, 80),
            status: 'free',
            x: 0,
            y: 0,
            width: 80,
            height: 80,
            shape: 'rectangle',
            is_object: isObject,
            object_type: objectType,
        });
        return newTableId;
    };

    const removeTable = async (envId: string, tableId: string) => {
        await deleteTableMutation({ tableId: tableId as Id<"tables"> });
    };

    const updateTable = async (envId: string, tableId: string, updates: Partial<Table>) => {
        await updateTableMutation({
            tableId: tableId as Id<"tables">,
            number: updates.number,
            capacity: updates.capacity,
            status: mapTableStatusToConvex(updates.status),
            x: updates.x,
            y: updates.y,
            width: updates.width,
            height: updates.height,
            rotation: updates.rotation,
            shape: updates.shape === 'round' ? 'circle' : (updates.shape as 'rectangle' | 'circle' | 'square'),
            chairs: updates.chairs,
            is_object: updates.isObject,
            object_type: updates.objectType,
        });
    };

    return {
        environments,
        isLoadingEnvironments,
        addEnvironment,
        removeEnvironment,
        updateEnvironment,
        addTable,
        removeTable,
        updateTable
    };
};
