import * as React from 'react';
import type { Device, DeviceType, ConnectionMethod, DeviceRole } from '@/types/devices';
import { useQuery, useMutation } from 'convex/react';
import { api } from '@/convex/_generated/api';
import { useEstablishments } from '@/hooks/useEstablishments';
import { Id } from '@/convex/_generated/dataModel';

// Helpers to map between Frontend Types and DB Schema
const mapTypeToDB = (type: DeviceType) => {
    if (type === 'pos') return 'pos_terminal';
    if (type === 'kds') return 'kds_station';
    return 'printer';
};

const mapDBToType = (type: string): DeviceType => {
    if (type === 'pos_terminal') return 'pos';
    if (type === 'kds_station') return 'kds';
    return 'printer';
};

const mapConnectionToDB = (conn: ConnectionMethod) => {
    if (conn === 'cable') return 'usb';
    return conn;
};

const mapDBToConnection = (conn: string): ConnectionMethod => {
    if (conn === 'usb') return 'cable';
    return conn as ConnectionMethod;
};

const mapRoleToDB = (role?: DeviceRole) => {
    if (role === 'kitchen') return 'kitchen';
    return 'main';
};

const mapDBToRole = (role: string): DeviceRole => {
    if (role === 'kitchen') return 'kitchen';
    return 'control';
};

export const useDevices = () => {
    const { activeEstablishment } = useEstablishments();
    const establishmentId = activeEstablishment?.id as Id<"establishments"> | undefined;

    const convexDevices = useQuery(api.devices.getDevicesByEstablishment,
        establishmentId ? { establishmentId } : "skip"
    );

    const createDeviceMutation = useMutation(api.devices.createDevice);
    const updateDeviceMutation = useMutation(api.devices.updateDevice);
    const deleteDeviceMutation = useMutation(api.devices.deleteDevice);

    // Map Convex data back to UI Model
    const devices: Device[] = React.useMemo(() => {
        if (!convexDevices) return [];
        return convexDevices.map(dbDev => ({
            id: dbDev._id,
            name: dbDev.name,
            model: 'Generic Model', // fallback since DB doesn't have it
            type: mapDBToType(dbDev.type),
            connectionMethod: mapDBToConnection(dbDev.connection),
            ipAddress: dbDev.ip_address,
            active: dbDev.status === 'online',
            role: mapDBToRole(dbDev.role),
            useForCashDrawer: false,
        }));
    }, [convexDevices]);

    const addDevice = async (deviceData: Omit<Device, 'id'>) => {
        if (!establishmentId) return;
        await createDeviceMutation({
            establishmentId,
            name: deviceData.name,
            type: mapTypeToDB(deviceData.type) as any,
            connection: mapConnectionToDB(deviceData.connectionMethod) as any,
            ip_address: deviceData.ipAddress,
            role: mapRoleToDB(deviceData.role) as any,
            status: deviceData.active ? 'online' : 'offline',
        });
    };

    const updateDevice = async (id: string, updates: Partial<Omit<Device, 'id'>>) => {
        await updateDeviceMutation({
            deviceId: id as Id<"devices">,
            name: updates.name,
            type: updates.type ? (mapTypeToDB(updates.type) as any) : undefined,
            connection: updates.connectionMethod ? (mapConnectionToDB(updates.connectionMethod) as any) : undefined,
            ip_address: updates.ipAddress,
            role: updates.role ? (mapRoleToDB(updates.role) as any) : undefined,
            status: updates.active !== undefined ? (updates.active ? 'online' : 'offline') : undefined,
        });
    };

    const removeDevice = async (id: string) => {
        await deleteDeviceMutation({ deviceId: id as Id<"devices"> });
    };

    return {
        devices,
        addDevice,
        updateDevice,
        removeDevice,
    };
};
